solutions.cpp:
#include <vector>
#include <stack>

class Solution {
public:
    typedef struct TreeNode* Node;
    vector<int> inorderTraversal(Node root) {
        vector<int> res;
        stack<Node> stack;
        while (!stack.empty() || root) {
            while (root) {
                stack.push(root);
                root = root->left;
            }
            root = stack.top();
            stack.pop();
            res.push_back(root->val);
            root = root->right;
        }
        return res;
    }
};
